// Find first unread email that looks like an NTR (Non-Trading Request).
// Keywords checked in subject — adjust as needed.
const NTR_KEYWORDS = ['non trading', 'non-trading', 'ntr request', 'trading request'];

const emails = ($input.first().json.value || []);

const match = emails.find(e => {
  const subj = (e.subject || '').toLowerCase();
  return NTR_KEYWORDS.some(kw => subj.includes(kw));
});

if (!match) {
  // No NTR email found — return empty to stop workflow gracefully
  return [];
}

// Extract store code from subject (e.g. 'HV06')
const storeFromSubject = (match.subject.match(/\b([A-Z]{2}\d{2,3})\b/i) || [])[1] || '';

return [{ json: {
  emailId:      match.id,
  subject:      match.subject || '',
  fromAddr:     match.from?.emailAddress?.address || '',
  receivedAt:   match.receivedDateTime || '',
  storeCode:    storeFromSubject.toUpperCase()
} }];

const emailMeta = $('Find First NTR Email').first().json;
const attachments = $input.first().json.value || [];

const xlsx = attachments.find(a =>
  !a.isInline &&
  a.contentBytes &&
  a.name &&
  a.name.toLowerCase().endsWith('.xlsx')
);

if (!xlsx) {
  // Email has no .xlsx — mark as read and stop
  throw new Error(`NTR email ${emailMeta.emailId} has no .xlsx attachment — skipping`);
}

// Try to get store code from the filename if not found in subject
const storeFromFile = (xlsx.name.match(/([A-Z]{2}\d{2,3})/i) || [])[1] || '';

return [{
  json: {
    emailId:         emailMeta.emailId,
    subject:         emailMeta.subject,
    fromAddr:        emailMeta.fromAddr,
    receivedAt:      emailMeta.receivedAt,
    storeCode:       (emailMeta.storeCode || storeFromFile).toUpperCase(),
    fileName:        xlsx.name
  },
  binary: {
    data: {
      data:     xlsx.contentBytes,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: xlsx.name
    }
  }
}];

// Mode: runOnceForAllItems — aggregates all Excel rows into one payload.
const meta = $('Prepare XLSX Binary').first().json;
const allRows = $input.all().map(i => i.json);

if (!allRows.length) throw new Error('Excel file has no data rows');

const first = allRows[0];
const storeCode   = meta.storeCode  || String(first['Store Code']  || '').trim().toUpperCase();
const storeName   = String(first['Store Name']        || '').trim();
const requestDate = String(first['Date of Request']   || '').trim();

const items = allRows
  .map(row => ({
    item_article_no:    String(row['Item Article No.']            || '').trim(),
    item_name:          String(row['Item Name']                   || '').trim(),
    last_received_date: String(row['Last Received Date to store'] || '').trim(),
    last_received_qty:  String(row['Last Received Qty in store']  || '').trim(),
    current_stock:      String(row['Current stock '] || row['Current stock'] || '').trim(),
    stock_days:         String(row['Stock is for how many days']  || '').trim(),
    store_requirement:  String(row['Store Requirement '] || row['Store Requirement'] || '').trim(),
    ho_recommendation:  String(row['HO-Admin Recommendation']     || '').trim(),
  }))
  .filter(r => r.item_article_no || r.item_name);

const today = new Date().toISOString().split('T')[0];

return [{ json: {
  storeCode,
  storeName,
  requestDate,
  receivedDate:   today,
  emailFrom:      meta.fromAddr       || '',
  emailSubject:   meta.subject        || '',
  emailMessageId: meta.emailId        || '',
  items,
  totalItems:     items.length
} }];
